@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _saving;
    private string? _successMessage;

    protected override void OnParametersSet()
    {
        if (_profile is null && Profile is not null)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        _profile = profile;
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        _saving = true;
        _successMessage = null;

        var updated = _profile with { DisplayName = _displayName, Email = _email, Bio = _bio };
        await OnSave.InvokeAsync(updated);

        _profile = updated;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        _successMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_70824896d1ff4e4ca36a8fd8c17b35b0.Models

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_prefs is not null)
    {
        <div class="mb-4">
            <h6 class="text-muted mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="text-muted mb-3">Muted Channels</h6>
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-secondary ms-2">Muted</span>
                        }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3">✅ @_successMessage</div>
        }
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _allChannels = ["general", "engineering", "marketing", "design", "random", "announcements"];

    protected override void OnParametersSet()
    {
        if (_prefs is null && Prefs is not null)
        {
            _prefs = Prefs;
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;

        var updated = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );

        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _saving = false;
        _successMessage = "Notification preferences saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_70824896d1ff4e4ca36a8fd8c17b35b0.Models

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />
    </div>

    @if (_settings is not null)
    {
        <div class="mb-4">
            <h6 class="text-muted mb-2">Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="twoFactor">
                        Enable Two-Factor Authentication
                    </label>
                </div>
                @if (_twoFactorEnabled)
                {
                    <span class="badge bg-success">Enabled</span>
                }
                else
                {
                    <span class="badge bg-secondary">Disabled</span>
                }
            </div>
            @if (_settings.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <div class="mb-4">
            <h6 class="text-muted mb-3">Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _settings.Sessions)
                        {
                            var isCurrentSession = session == _settings.Sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrentSession)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrentSession)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    }

    @if (_sessionToRevoke is not null)
    {
        <RevokeSessionDialog
            Device="@_sessionToRevoke.Device"
            Location="@_sessionToRevoke.Location"
            OnConfirm="ConfirmRevokeAsync"
            OnCancel="CancelRevoke" />
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            _settings = Settings;
            _twoFactorEnabled = Settings.TwoFactorEnabled;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

