}

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
}

/* ===== Sidebar Navigation ===== */
.settings-sidebar {
    padding: 1rem 0;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    width: 100%;
    padding: 0.6rem 1.25rem;
    border: none;
    background: none;
    color: #495057;
    font-size: 0.95rem;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

/* ===== Section Shared ===== */
.settings-section {
    animation: fadeIn 0.2s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(4px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ===== Avatar Preview ===== */
.avatar-preview img {
    border: 3px solid #dee2e6;
    object-fit: cover;
}

/* ===== Appearance Live Preview ===== */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.75rem;
}

.preview-label {
    font-weight: 600;
    display: block;
    margin-bottom: 0.25rem;
}

.preview-description {
    margin-bottom: 0;
    font-size: 0.9em;
}

.preview-button {
    padding: 0.4rem 1rem;
    border-radius: 4px;
    border: none;
    font-weight: 500;
    cursor: default;
}

/* Theme: Light */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-light .preview-header {
    background: #f8f9fa;
}

.preview-theme-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

/* Theme: Dark */
.preview-theme-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-theme-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-theme-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-theme-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

/* Theme: System — show a split light/dark */
.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
