@using sv_70824896d1ff4e4ca36a8fd8c17b35b0.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-sidebar-container">
        <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="SetActiveSection" />
    </div>
    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_savedProfile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="@_securitySettings"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearanceSettings" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _savedProfile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
        _loading = false;
    }

    private async Task LoadAllSettingsAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _savedProfile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _securitySettings = securityTask.Result;
        _appearanceSettings = appearanceTask.Result;
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) passwords)
    {
        await SettingsService.ChangePasswordAsync(passwords.Current, passwords.New);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
    }
}

/* ===== Settings Dashboard Layout ===== */
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
}

.settings-sidebar-container {
    width: 240px;
    flex-shrink: 0;
    border-right: 1px solid #e0e0e0;
    background: #f8f9fa;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
}

/* ===== Sidebar Navigation ===== */
.settings-sidebar {
    padding: 1rem 0;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    width: 100%;
    padding: 0.6rem 1.25rem;
    border: none;
    background: none;
    color: #495057;
    font-size: 0.95rem;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

/* ===== Section Shared ===== */
.settings-section {
    animation: fadeIn 0.2s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(4px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ===== Avatar Preview ===== */
.avatar-preview img {
    border: 3px solid #dee2e6;
    object-fit: cover;
}

/* ===== Appearance Live Preview ===== */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.75rem;
}

.preview-label {
    font-weight: 600;
    display: block;
    margin-bottom: 0.25rem;
}

.preview-description {
    margin-bottom: 0;
    font-size: 0.9em;
}

.preview-button {
    padding: 0.4rem 1rem;
    border-radius: 4px;
    border: none;
    font-weight: 500;
    cursor: default;
}

/* Theme: Light */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-light .preview-header {
    background: #f8f9fa;
}

.preview-theme-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

/* Theme: Dark */
.preview-theme-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-theme-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-theme-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-theme-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

/* Theme: System — show a split light/dark */
.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #495057;
}

.preview-theme-system .preview-header {
    background: rgba(0,0,0,0.05);
}

.preview-theme-system .preview-button {
    background: #6c63ff;
    color: #fff;
}

/* Font sizes */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-card {
    padding: 0.4rem 0.5rem;
    margin-bottom: 0.4rem;
}

/* ===== Modal backdrop fix ===== */
.modal-backdrop.show {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    z-index: 1040;
}

.modal.d-block {
    position: fixed;
    z-index: 1050;
}

