@using sv_70824896d1ff4e4ca36a8fd8c17b35b0.Models

<div class="settings-section">
    <h4 class="mb-4">Appearance</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="mb-4">
                <h6 class="text-muted mb-2">Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6 class="text-muted mb-2">Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6 class="text-muted mb-2">Language</h6>
                <select class="form-select" style="max-width: 250px;"
                        @onchange="e => _language = e.Value?.ToString() ?? _language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang" selected="@(_language == lang)">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <h6 class="text-muted mb-2">Layout</h6>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3">✅ @_successMessage</div>
            }
        </div>

        <div class="col-md-5">
            <h6 class="text-muted mb-2">Live Preview</h6>
            <div class="appearance-preview @GetPreviewClasses()">
                <div class="preview-header">
                    <strong>Preview</strong>
                </div>
                <div class="preview-body">
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <div class="preview-card">
                        <span class="preview-label">Sample Card</span>
                        <p class="preview-description">A quick preview of the appearance options you've selected.</p>
                    </div>
                    <button class="preview-button">Sample Button</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;

        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _successMessage = "Appearance settings saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

